import { useEffect, useState } from "react";
import api from "../../api/axios";
import { useNavigate } from "react-router-dom";

export default function LeadList() {
  const [leads, setLeads] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    api.get("/leads").then(res => setLeads(res.data));
  }, []);

  return (
    <div style={{ padding: 20 }}>
      <h2>Leads</h2>

      <button onClick={() => navigate("/leads/new")}>
        + Add Lead
      </button>

      <table border="1" cellPadding="8" style={{ marginTop: 15, width: "100%" }}>
        <thead>
          <tr>
            <th>Name</th>
            <th>Contact</th>
            <th>Email</th>
            <th>Source</th>
            <th>Interest</th>
            <th>Status</th>
            <th>Edit</th>
          </tr>
        </thead>
        <tbody>
          {leads.map(lead => (
            <tr key={lead._id}>
              <td>{lead.name}</td>
              <td>{lead.contact_number}</td>
              <td>{lead.email}</td>
              <td>{lead.lead_source}</td>
              <td>{lead.interest_level}</td>
              <td>{lead.status}</td>
              <td>
                <button onClick={() => navigate(`/leads/${lead._id}`)}>
                  Edit
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
